/*
# Expand database - Batch 2c: Government policies

## Summary
Adds 30 important Indian government policies covering rights, laws, and
governance frameworks that citizens should know about.

## Notes
- Uses ON CONFLICT (slug) DO NOTHING for idempotency.
- No destructive operations; pure INSERT.
*/

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'policies_slug_key') THEN
    ALTER TABLE policies ADD CONSTRAINT policies_slug_key UNIQUE (slug);
  END IF;
END $$;

INSERT INTO policies (title, slug, category, summary, content, key_points, official_reference, tags, published, last_verified_at, faq_list)
VALUES
('Right to Education (RTE) Act', 'right-to-education-act', 'Education',
 'The RTE Act guarantees free and compulsory education to all children aged 6-14.',
 'The Right of Children to Free and Compulsory Education (RTE) Act, 2009 guarantees free and compulsory education to all children aged 6-14 years. It mandates that 25% of seats in private schools be reserved for economically disadvantaged students.',
 '["Free education for children aged 6-14","25% reservation in private schools for EWS","No capitation fee or screening test","Trained and qualified teachers","Infrastructure norms for schools","No child held back or expelled until Class 8"]',
 'RTE Act, 2009 (Act 35 of 2009)',
 '["education","rte","right","children","free","compulsory"]', true, now(), '[]'),
('National Education Policy 2020', 'national-education-policy-2020', 'Education',
 'NEP 2020 transforms Indian education with a 5+3+3+4 structure and multidisciplinary approach.',
 'The National Education Policy (NEP) 2020 envisions a comprehensive overhaul of the Indian education system. It introduces a 5+3+3+4 pedagogical structure, multidisciplinary education, multiple entry/exit options, and mother tongue instruction until Class 5.',
 '["5+3+3+4 structure (Foundational, Preparatory, Middle, Secondary)","Mother tongue instruction until Class 5","Multiple entry and exit in higher education","4-year integrated teacher education","Single regulator for higher education (HECI)","Target: 50% GER in higher education by 2035"]',
 'NEP 2020 (Ministry of Education, GoI)',
 '["education","nep","policy","reform","multidisciplinary"]', true, now(), '[]'),
('Consumer Protection Act 2019', 'consumer-protection-act-2019', 'Rights',
 'The Consumer Protection Act 2019 strengthens consumer rights with e-commerce rules and CCPA.',
 'The Consumer Protection Act, 2019 replaced the 1986 Act. It establishes the Central Consumer Protection Authority (CCPA), covers e-commerce, product liability, and direct selling. Consumers can file complaints online and seek faster redressal.',
 '["CCPA for class action and enforcement","E-commerce rules for online shopping","Product liability for defective goods","Mediation as dispute resolution","No fee for complaints up to Rs. 5 lakh","Video conferencing for hearings"]',
 'Consumer Protection Act, 2019 (Act 35 of 2019)',
 '["consumer","rights","protection","ecommerce","ccpa","liability"]', true, now(), '[]'),
('Right to Information Act 2005', 'right-to-information-act-2005', 'Rights',
 'The RTI Act empowers citizens to request information from public authorities.',
 'The Right to Information (RTI) Act, 2005 empowers Indian citizens to request information from public authorities. It mandates timely response (within 30 days) and promotes transparency and accountability in governance.',
 '["Any citizen can file RTI","Application fee: Rs. 10 (central)","Response within 30 days (48 hours if life/liberty)","First appeal within 30 days of denial","Second appeal to CIC/SIC within 90 days","Free for BPL applicants"]',
 'RTI Act, 2005 (Act 22 of 2005)',
 '["rti","right to information","transparency","governance","citizen"]', true, now(), '[]'),
('Digital Personal Data Protection Act 2023', 'dpdp-act-2023', 'Digital',
 'The DPDP Act 2023 regulates processing of digital personal data and protects citizen privacy.',
 'The Digital Personal Data Protection (DPDP) Act, 2023 regulates the processing of digital personal data. It establishes rights for data principals (citizens) and obligations for data fiduciaries (entities processing data). It aims to protect individual privacy in the digital economy.',
 '["Consent required for data processing","Right to access, correct, erase data","Data Protection Board for grievances","Significant data fiduciaries have extra obligations","Children data requires verifiable parental consent","Penalties up to Rs. 250 crore for violations"]',
 'DPDP Act, 2023 (Act 22 of 2023)',
 '["data","privacy","digital","protection","dpdp","consent"]', true, now(), '[]'),
('Goods and Services Tax (GST) Act', 'gst-act', 'Tax',
 'GST unified indirect taxation with one tax across India for goods and services.',
 'The Goods and Services Tax (GST) Act, 2017 unified multiple indirect taxes into a single tax. It has CGST, SGST, and IGST components with rates of 0%, 5%, 12%, 18%, and 28%. GST replaced VAT, service tax, excise duty, and other indirect taxes.',
 '["Single tax for goods and services","Rates: 0%, 5%, 12%, 18%, 28%","Threshold: Rs. 20 lakh (services), Rs. 40 lakh (goods)","GSTIN: 15-digit unique ID","GST Council decides rates","Composition scheme for small businesses"]',
 'CGST Act, 2017 (Act 13 of 2017)',
 '["gst","tax","indirect","goods","services","cgst","igst"]', true, now(), '[]'),
('Labour Codes 2020', 'labour-codes-2020', 'Employment',
 'Four labour codes consolidate 29 labour laws into 4 codes covering wages, industrial relations, social security, and occupational safety.',
 'The Government of India consolidated 29 labour laws into 4 labour codes: Code on Wages, Industrial Relations Code, Social Security Code, and Occupational Safety, Health and Working Conditions Code. These codes simplify compliance and expand coverage.',
 '["Code on Wages: Universal minimum wage","Industrial Relations Code: Fixed-term employment","Social Security Code: Gig workers covered","OSH Code: Inter-state migrant workers","One license, one registration","Digital compliance and records"]',
 'Labour Codes 2020 (4 Acts of 2020)',
 '["labour","employment","wages","social security","safety","code"]', true, now(), '[]'),
('National Health Policy 2017', 'national-health-policy-2017', 'Health',
 'The National Health Policy 2017 aims to achieve universal health coverage and reduce out-of-pocket spending.',
 'The National Health Policy 2017 aims to achieve the highest possible level of health and well-being for all ages. It targets reducing out-of-pocket expenditure, increasing health spending, and achieving universal health coverage through Ayushman Bharat.',
 '["Increase health spending to 2.5% of GDP","Reduce out-of-pocket expenditure","Ayushman Bharat: PM-JAY and HWCs","Free drugs and diagnostics in public facilities","Health and wellness centers","Target: 90% immunization by 2025"]',
 'National Health Policy 2017 (Ministry of Health)',
 '["health","policy","universal","coverage","ayushman","pmjay"]', true, now(), '[]'),
('National Policy for Persons with Disabilities 2006', 'disability-policy-2006', 'Disability',
 'The policy ensures full participation and equal opportunities for persons with disabilities.',
 'The National Policy for Persons with Disabilities, 2006 recognizes that persons with disabilities are valuable human resources. It focuses on prevention, rehabilitation, and empowerment. The Rights of Persons with Disabilities (RPwD) Act, 2016 expanded rights and reservation.',
